import type { CalculatorSettings, ComputationIssue, WorkspaceState, WorkspaceToolId } from "@core/contracts";
import type { HistoryEntry, HistoryModeMetadata } from "../features/history/model";
import type { MemoryRegister } from "../features/memory/model";

export interface WorkspacePresentation {
  tool: WorkspaceToolId;
  title: string;
  detail: string;
  value: string;
  issues: ComputationIssue[];
}

function formatMatrixLabel(rows: number, columns: number): string {
  return `${rows} x ${columns}`;
}

export function buildModeMetadata(settings: CalculatorSettings): HistoryModeMetadata {
  return {
    backend: settings.numeric.backend,
    angleMode: settings.numeric.angleMode,
    displayMode: settings.numeric.displayMode,
    displayPrecision: settings.numeric.displayPrecision
  };
}

export function summarizeWorkspace(workspace: WorkspaceState): WorkspacePresentation {
  switch (workspace.activeTool) {
    case "calculate":
      return {
        tool: "calculate",
        title: "Expression Draft",
        detail: workspace.expressionInput.trim() || "No expression drafted yet.",
        value: workspace.expressionInput.trim() || "Awaiting input",
        issues: workspace.expressionInput.trim()
          ? []
          : [{ code: "empty-expression", message: "Add an expression to capture a useful snapshot.", severity: "warning" }]
      };
    case "matrix":
      return {
        tool: "matrix",
        title: "Matrix Workspace",
        detail: `Left ${formatMatrixLabel(workspace.matrix.left.rows, workspace.matrix.left.columns)} / Right ${formatMatrixLabel(
          workspace.matrix.right?.rows ?? 2,
          workspace.matrix.right?.columns ?? 2
        )}`,
        value: `Ready for persisted matrix drafts`,
        issues: []
      };
    case "solver":
      return {
        tool: "solver",
        title: "Solver Draft",
        detail: workspace.solver.expression.trim() || "No solver expression drafted yet.",
        value: `${workspace.solver.method} | x0=${workspace.solver.initialGuess}`,
        issues: workspace.solver.expression.trim()
          ? []
          : [{ code: "empty-solver-expression", message: "Add a solver expression before storing a snapshot.", severity: "warning" }]
      };
    case "numerical":
      return {
        tool: "numerical",
        title: "Numerical Draft",
        detail: workspace.numerical.expression.trim() || "No numerical expression drafted yet.",
        value: `${workspace.numerical.tool} | [${workspace.numerical.intervalStart}, ${workspace.numerical.intervalEnd}]`,
        issues: workspace.numerical.expression.trim()
          ? []
          : [{ code: "empty-numerical-expression", message: "Add an expression before storing a numerical snapshot.", severity: "warning" }]
      };
  }
}

export function createHistoryEntry(
  workspace: WorkspaceState,
  settings: CalculatorSettings,
  timestamp: string,
  id: string
): HistoryEntry {
  const presentation = summarizeWorkspace(workspace);

  return {
    id,
    tool: presentation.tool,
    title: presentation.title,
    detail: presentation.detail,
    value: presentation.value,
    createdAt: timestamp,
    mode: buildModeMetadata(settings)
  };
}

export function captureRegister(
  register: MemoryRegister,
  workspace: WorkspaceState,
  settings: CalculatorSettings,
  timestamp: string
): MemoryRegister {
  const presentation = summarizeWorkspace(workspace);

  return {
    ...register,
    value: presentation.value,
    detail: presentation.detail,
    sourceTool: presentation.tool,
    updatedAt: timestamp,
    mode: buildModeMetadata(settings)
  };
}

import type { CalculatorSettings, WorkspaceState } from "@core/contracts";
import type { HistoryEntry } from "../features/history/model";
import type { MemoryRegister } from "../features/memory/model";
import {
  HISTORY_SCHEMA_VERSION,
  MEMORY_SCHEMA_VERSION,
  SETTINGS_SCHEMA_VERSION,
  WORKSPACE_SCHEMA_VERSION,
  createDefaultHistoryDocument,
  createDefaultMemoryDocument,
  createDefaultSettingsDocument,
  createDefaultWorkspaceDocument,
  parsePersistedHistory,
  parsePersistedMemory,
  parsePersistedSettings,
  parsePersistedWorkspace,
  type PersistedHistoryDocument,
  type PersistedMemoryDocument,
  type PersistedSettingsDocument,
  type PersistedWorkspaceDocument
} from "./schema";
import { sanitizeCalculatorSettings } from "../features/settings/model";
import { sanitizeWorkspaceState } from "../app/workspaceDrafts";

const STORAGE_KEYS = {
  settings: "calculator.settings.v1",
  workspace: "calculator.workspace.v1",
  history: "calculator.history.v1",
  memory: "calculator.memory.v1"
} as const;

export interface StorageLike {
  getItem(key: string): string | null;
  setItem(key: string, value: string): void;
  removeItem(key: string): void;
}

export interface PersistenceSnapshot {
  settings: PersistedSettingsDocument;
  workspace: PersistedWorkspaceDocument;
  history: PersistedHistoryDocument;
  memory: PersistedMemoryDocument;
}

type Clock = () => string;

function readDocument<TDocument>(
  storage: StorageLike,
  key: string,
  parse: (value: unknown) => TDocument | null,
  fallback: () => TDocument
): TDocument {
  const raw = storage.getItem(key);
  if (raw === null) {
    return fallback();
  }

  try {
    const parsed = JSON.parse(raw) as unknown;
    return parse(parsed) ?? fallback();
  } catch {
    return fallback();
  }
}

function writeDocument(storage: StorageLike, key: string, value: unknown): void {
  storage.setItem(key, JSON.stringify(value));
}

export function createMemoryStorage(): StorageLike {
  const values = new Map<string, string>();

  return {
    getItem(key) {
      return values.get(key) ?? null;
    },
    setItem(key, value) {
      values.set(key, value);
    },
    removeItem(key) {
      values.delete(key);
    }
  };
}

export function getBrowserStorage(): StorageLike {
  if (typeof window === "undefined") {
    return createMemoryStorage();
  }

  try {
    return window.localStorage;
  } catch {
    return createMemoryStorage();
  }
}

export function createCalculatorPersistence(storage: StorageLike, now: Clock = () => new Date().toISOString()) {
  return {
    loadSnapshot(): PersistenceSnapshot {
      return {
        settings: readDocument(storage, STORAGE_KEYS.settings, parsePersistedSettings, createDefaultSettingsDocument),
        workspace: readDocument(storage, STORAGE_KEYS.workspace, parsePersistedWorkspace, createDefaultWorkspaceDocument),
        history: readDocument(storage, STORAGE_KEYS.history, parsePersistedHistory, createDefaultHistoryDocument),
        memory: readDocument(storage, STORAGE_KEYS.memory, parsePersistedMemory, createDefaultMemoryDocument)
      };
    },
    saveSettings(payload: CalculatorSettings): PersistedSettingsDocument {
      const document: PersistedSettingsDocument = {
        version: SETTINGS_SCHEMA_VERSION,
        updatedAt: now(),
        payload: sanitizeCalculatorSettings(payload)
      };
      writeDocument(storage, STORAGE_KEYS.settings, document);
      return document;
    },
    saveWorkspace(payload: WorkspaceState): PersistedWorkspaceDocument {
      const document: PersistedWorkspaceDocument = {
        version: WORKSPACE_SCHEMA_VERSION,
        updatedAt: now(),
        payload: sanitizeWorkspaceState(payload)
      };
      writeDocument(storage, STORAGE_KEYS.workspace, document);
      return document;
    },
    saveHistory(entries: HistoryEntry[]): PersistedHistoryDocument {
      const document: PersistedHistoryDocument = {
        version: HISTORY_SCHEMA_VERSION,
        updatedAt: now(),
        payload: {
          entries
        }
      };
      writeDocument(storage, STORAGE_KEYS.history, document);
      return document;
    },
    saveMemory(registers: MemoryRegister[]): PersistedMemoryDocument {
      const document: PersistedMemoryDocument = {
        version: MEMORY_SCHEMA_VERSION,
        updatedAt: now(),
        payload: {
          registers
        }
      };
      writeDocument(storage, STORAGE_KEYS.memory, document);
      return document;
    }
  };
}

import { useState } from "react";
import type {
  CalculatorSettings,
  ComputationIssue,
  LinearSystemResult,
  MatrixData,
  MatrixDraft,
  MatrixOperation,
  MatrixOperationResult,
  ResultEnvelope
} from "@core/contracts";
import { MAX_MATRIX_SIZE } from "@core/matrix";
import { createMatrixService } from "../../services/matrix";

type MatrixAction = MatrixOperation | "solve";

interface MatrixWorkbenchProps {
  settings: CalculatorSettings;
  initialDraft: MatrixDraft;
}

const matrixService = createMatrixService();

const actionLabels: Record<MatrixAction, string> = {
  add: "Add",
  subtract: "Subtract",
  multiply: "Multiply",
  transpose: "Transpose",
  determinant: "Determinant",
  inverse: "Inverse",
  solve: "Solve Ax = b"
};

const binaryActions: MatrixAction[] = ["add", "subtract", "multiply"];

export function MatrixWorkbench({ settings, initialDraft }: MatrixWorkbenchProps) {
  const [action, setAction] = useState<MatrixAction>("solve");
  const [leftSize, setLeftSize] = useState({ rows: initialDraft.left.rows, columns: initialDraft.left.columns });
  const [rightSize, setRightSize] = useState({
    rows: initialDraft.right?.rows ?? initialDraft.left.rows,
    columns: initialDraft.right?.columns ?? initialDraft.left.columns
  });
  const [leftValues, setLeftValues] = useState(() => toDraftValues(initialDraft.left));
  const [rightValues, setRightValues] = useState(() => toDraftValues(initialDraft.right ?? initialDraft.left));
  const [rightHandSide, setRightHandSide] = useState(() => createVectorDraft(initialDraft.left.rows));
  const [result, setResult] = useState<ResultEnvelope<MatrixOperationResult | LinearSystemResult> | null>(null);

  const usesRightMatrix = binaryActions.includes(action);
  const usesRightHandSide = action === "solve";

  function updateLeftSize(nextRows: number, nextColumns: number) {
    setLeftSize({ rows: nextRows, columns: nextColumns });
    setLeftValues((current) => resizeDraftMatrix(current, nextRows, nextColumns));
    setRightHandSide((current) => resizeDraftVector(current, nextRows));
  }

  function updateRightSize(nextRows: number, nextColumns: number) {
    setRightSize({ rows: nextRows, columns: nextColumns });
    setRightValues((current) => resizeDraftMatrix(current, nextRows, nextColumns));
  }

  function submit() {
    if (action === "solve") {
      const coefficientMatrix = parseMatrixDraft(leftValues, leftSize.rows, leftSize.columns);
      const vector = parseVectorDraft(rightHandSide, leftSize.rows);

      if (!coefficientMatrix.ok) {
        setResult(failEnvelope(settings, [coefficientMatrix.issue]));
        return;
      }

      if (!vector.ok) {
        setResult(failEnvelope(settings, [vector.issue]));
        return;
      }

      void Promise.resolve(
        matrixService.solveLinearSystem({
          matrix: coefficientMatrix.value,
          rightHandSide: vector.value,
          settings
        })
      ).then((response) => setResult(response));
      return;
    }

    const leftMatrix = parseMatrixDraft(leftValues, leftSize.rows, leftSize.columns);
    if (!leftMatrix.ok) {
      setResult(failEnvelope(settings, [leftMatrix.issue]));
      return;
    }

    const rightMatrix = usesRightMatrix
      ? parseMatrixDraft(rightValues, rightSize.rows, rightSize.columns)
      : null;

    if (rightMatrix !== null && !rightMatrix.ok) {
      setResult(failEnvelope(settings, [rightMatrix.issue]));
      return;
    }

    const request =
      rightMatrix !== null
        ? {
            operation: action,
            left: leftMatrix.value,
            right: rightMatrix.value,
            settings
          }
        : {
            operation: action,
            left: leftMatrix.value,
            settings
          };

    void Promise.resolve(matrixService.evaluate(request)).then((response) => setResult(response));
  }

  function resetDrafts() {
    setLeftSize({ rows: initialDraft.left.rows, columns: initialDraft.left.columns });
    setRightSize({
      rows: initialDraft.right?.rows ?? initialDraft.left.rows,
      columns: initialDraft.right?.columns ?? initialDraft.left.columns
    });
    setLeftValues(toDraftValues(initialDraft.left));
    setRightValues(toDraftValues(initialDraft.right ?? initialDraft.left));
    setRightHandSide(createVectorDraft(initialDraft.left.rows));
    setResult(null);
  }

  return (
    <section className="matrix-workbench">
      <header className="matrix-toolbar">
        <div>
          <p className="eyebrow">Matrix mode</p>
          <h3>Stable linear algebra workspace</h3>
          <p className="matrix-caption">
            Partial pivoting is used for determinant, inverse, and linear solve. Matrix sizes are limited to
            2 through {MAX_MATRIX_SIZE} per dimension in this workflow.
          </p>
        </div>
        <div className="matrix-toolbar-actions">
          <label className="field-stack">
            <span>Action</span>
            <select value={action} onChange={(event) => setAction(event.target.value as MatrixAction)}>
              {(Object.keys(actionLabels) as MatrixAction[]).map((candidate) => (
                <option key={candidate} value={candidate}>
                  {actionLabels[candidate]}
                </option>
              ))}
            </select>
          </label>
          <button type="button" className="secondary-button" onClick={resetDrafts}>
            Reset drafts
          </button>
          <button type="button" className="primary-button" onClick={submit}>
            Run matrix task
          </button>
        </div>
      </header>

      <div className="matrix-meta-strip">
        <span>Backend: {settings.numeric.backend}</span>
        <span>Tolerance: {formatCompact(settings.numeric.solverTolerance)}</span>
        <span>Display: {settings.numeric.displayMode}</span>
        <span>Precision: {settings.numeric.displayPrecision} digits</span>
      </div>

      <div className="matrix-pane-grid">
        <MatrixEditor
          title="Left matrix A"
          size={leftSize}
          values={leftValues}
          onSizeChange={updateLeftSize}
          onValuesChange={setLeftValues}
        />

        {usesRightMatrix ? (
          <MatrixEditor
            title="Right matrix B"
            size={rightSize}
            values={rightValues}
            onSizeChange={updateRightSize}
            onValuesChange={setRightValues}
          />
        ) : usesRightHandSide ? (
          <VectorEditor values={rightHandSide} onValuesChange={setRightHandSide} />
        ) : (
          <article className="matrix-pane matrix-note-pane">
            <h4>Unary operation</h4>
            <p className="matrix-caption">
              This action only uses matrix A. The result panel shows the transformed matrix or scalar output
              together with singularity and conditioning diagnostics when relevant.
            </p>
          </article>
        )}
      </div>

      <ResultPanel result={result} settings={settings} />
    </section>
  );
}

interface MatrixEditorProps {
  title: string;
  size: {
    rows: number;
    columns: number;
  };
  values: string[][];
  onSizeChange: (rows: number, columns: number) => void;
  onValuesChange: (values: string[][]) => void;
}

function MatrixEditor({ title, size, values, onSizeChange, onValuesChange }: MatrixEditorProps) {
  return (
    <article className="matrix-pane">
      <header className="matrix-pane-header">
        <h4>{title}</h4>
        <div className="matrix-dimension-controls">
          <label className="field-stack">
            <span>Rows</span>
            <select
              value={size.rows}
              onChange={(event) => onSizeChange(Number(event.target.value), size.columns)}
            >
              {dimensionOptions()}
            </select>
          </label>
          <label className="field-stack">
            <span>Columns</span>
            <select
              value={size.columns}
              onChange={(event) => onSizeChange(size.rows, Number(event.target.value))}
            >
              {dimensionOptions()}
            </select>
          </label>
        </div>
      </header>
      <div
        className="matrix-grid"
        style={{ gridTemplateColumns: `repeat(${size.columns}, minmax(0, 1fr))` }}
      >
        {values.map((row, rowIndex) =>
          row.map((value, columnIndex) => (
            <input
              key={`${rowIndex}-${columnIndex}`}
              className="matrix-cell"
              type="text"
              inputMode="decimal"
              value={value}
              onChange={(event) =>
                onValuesChange(
                  values.map((candidateRow, candidateRowIndex) =>
                    candidateRowIndex === rowIndex
                      ? candidateRow.map((candidateValue, candidateColumnIndex) =>
                          candidateColumnIndex === columnIndex ? event.target.value : candidateValue
                        )
                      : candidateRow
                  )
                )
              }
            />
          ))
        )}
      </div>
    </article>
  );
}

interface VectorEditorProps {
  values: string[];
  onValuesChange: (values: string[]) => void;
}

function VectorEditor({ values, onValuesChange }: VectorEditorProps) {
  return (
    <article className="matrix-pane">
      <header className="matrix-pane-header">
        <h4>Right-hand side b</h4>
        <p className="matrix-caption">Enter one entry per row of matrix A.</p>
      </header>
      <div className="vector-grid">
        {values.map((value, index) => (
          <input
            key={index}
            className="matrix-cell"
            type="text"
            inputMode="decimal"
            value={value}
            onChange={(event) =>
              onValuesChange(
                values.map((candidate, candidateIndex) =>
                  candidateIndex === index ? event.target.value : candidate
                )
              )
            }
          />
        ))}
