describe("numerical tools service", () => {
  it("differentiates with angle-aware central differences", async () => {
    const service = createNumericalToolsService();
    const result = await service.run({
      tool: "differentiate",
      expression: "sin(x)",
      point: 0,
      differentiationMethod: "central",
      settings: makeSettings({
        angleMode: "degree",
        solverTolerance: 1e-8
      })
    });

    expect(result.ok).toBe(true);
    if (!result.ok) {
      return;
    }

    expect(result.value.method).toBe("central");
    expect(result.value.approximateValue).toBeCloseTo(Math.PI / 180, 6);
  });

  it("integrates smooth functions accurately with Simpson panels", async () => {
    const service = createNumericalToolsService();
    const result = await service.run({
      tool: "integrate",
      expression: "x^2",
      interval: [0, 1],
      integrationMethod: "simpson",
      settings: makeSettings({
        solverTolerance: 1e-10
      })
    });

    expect(result.ok).toBe(true);
    if (!result.ok) {
      return;
    }

    expect(result.value.method).toBe("simpson");
    expect(result.value.approximateValue).toBeCloseTo(1 / 3, 10);
    expect(result.issues).toEqual([]);
  });

  it("surfaces a warning near non-smooth derivative points", async () => {
    const service = createNumericalToolsService();
    const result = await service.run({
      tool: "differentiate",
      expression: "abs(x)",
      point: 0,
      differentiationMethod: "central",
      settings: makeSettings({
        solverTolerance: 1e-10
      })
    });

    expect(result.ok).toBe(true);
    if (!result.ok) {
      return;
    }

    expect(result.issues.map((issue) => issue.code)).toContain("numerical.point_nonsmooth");
  });

  it("warns when trapezoidal refinement exhausts the panel budget", async () => {
    const service = createNumericalToolsService();
    const result = await service.run({
      tool: "integrate",
      expression: "sin(x)",
      interval: [0, Math.PI],
      integrationMethod: "trapezoidal",
      settings: makeSettings({
        solverTolerance: 1e-12,
        maxIterations: 4
      })
    });

    expect(result.ok).toBe(true);
    if (!result.ok) {
      return;
    }

    expect(result.issues.map((issue) => issue.code)).toContain("numerical.integration_not_converged");
  });

  it("fails clearly when the integrand is singular at an endpoint", async () => {
    const service = createNumericalToolsService();
    const result = await service.run({
      tool: "integrate",
      expression: "1 / sqrt(x)",
      interval: [0, 1],
      integrationMethod: "simpson",
      settings: makeSettings()
    });

    expect(result.ok).toBe(false);
    if (result.ok) {
      return;
    }

    expect(result.issues[0]?.code).toBe("math.division_by_zero");
  });
});

import type { CalculatorSettings, MatrixData, WorkspaceState } from "@core/contracts";
import type { HistoryEntry, HistoryModeMetadata } from "../features/history/model";
import type { MemoryRegister } from "../features/memory/model";
import { createDefaultMemoryRegisters } from "../features/memory/model";
import { createDefaultWorkspaceState, sanitizeWorkspaceState } from "../app/workspaceDrafts";
import { createDefaultCalculatorSettings, sanitizeCalculatorSettings } from "../features/settings/model";

export const SETTINGS_SCHEMA_VERSION = 1 as const;
export const WORKSPACE_SCHEMA_VERSION = 1 as const;
export const HISTORY_SCHEMA_VERSION = 1 as const;
export const MEMORY_SCHEMA_VERSION = 1 as const;

export interface VersionedDocument<TVersion extends number, TPayload> {
  version: TVersion;
  payload: TPayload;
  updatedAt: string;
}

export type PersistedSettingsDocument = VersionedDocument<typeof SETTINGS_SCHEMA_VERSION, CalculatorSettings>;
export type PersistedWorkspaceDocument = VersionedDocument<typeof WORKSPACE_SCHEMA_VERSION, WorkspaceState>;
export type PersistedHistoryDocument = VersionedDocument<typeof HISTORY_SCHEMA_VERSION, { entries: HistoryEntry[] }>;
export type PersistedMemoryDocument = VersionedDocument<typeof MEMORY_SCHEMA_VERSION, { registers: MemoryRegister[] }>;

const DEFAULT_UPDATED_AT = new Date(0).toISOString();

export function createDefaultSettingsDocument(): PersistedSettingsDocument {
  return {
    version: SETTINGS_SCHEMA_VERSION,
    updatedAt: DEFAULT_UPDATED_AT,
    payload: createDefaultCalculatorSettings()
  };
}

export function createDefaultWorkspaceDocument(): PersistedWorkspaceDocument {
  return {
    version: WORKSPACE_SCHEMA_VERSION,
    updatedAt: DEFAULT_UPDATED_AT,
    payload: createDefaultWorkspaceState()
  };
}

export function createDefaultHistoryDocument(): PersistedHistoryDocument {
  return {
    version: HISTORY_SCHEMA_VERSION,
    updatedAt: DEFAULT_UPDATED_AT,
    payload: {
      entries: []
    }
  };
}

export function createDefaultMemoryDocument(): PersistedMemoryDocument {
  return {
    version: MEMORY_SCHEMA_VERSION,
    updatedAt: DEFAULT_UPDATED_AT,
    payload: {
      registers: createDefaultMemoryRegisters()
    }
  };
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function isMatrixData(value: unknown): value is MatrixData {
  if (!isRecord(value)) {
    return false;
  }

  return (
    typeof value.rows === "number" &&
    typeof value.columns === "number" &&
    Array.isArray(value.values) &&
    value.values.every(
      (row) => Array.isArray(row) && row.every((entry) => typeof entry === "number")
    )
  );
}

function isCalculatorSettings(value: unknown): value is CalculatorSettings {
  if (!isRecord(value) || !isRecord(value.numeric)) {
    return false;
  }

  const numeric = value.numeric;

  return (
    (numeric.backend === "float64" || numeric.backend === "decimal") &&
    typeof numeric.displayPrecision === "number" &&
    typeof numeric.internalPrecision === "number" &&
    typeof numeric.solverTolerance === "number" &&
    typeof numeric.maxIterations === "number" &&
    (numeric.angleMode === "degree" || numeric.angleMode === "radian") &&
    (numeric.displayMode === "normal" ||
      numeric.displayMode === "scientific" ||
      numeric.displayMode === "engineering") &&
    typeof value.locale === "string"
  );
}

function isHistoryModeMetadata(value: unknown): value is HistoryModeMetadata {
  return (
    isRecord(value) &&
    (value.backend === "float64" || value.backend === "decimal") &&
    (value.angleMode === "degree" || value.angleMode === "radian") &&
    (value.displayMode === "normal" || value.displayMode === "scientific" || value.displayMode === "engineering") &&
    typeof value.displayPrecision === "number"
  );
}

function isHistoryEntry(value: unknown): value is HistoryEntry {
  return (
    isRecord(value) &&
    typeof value.id === "string" &&
    (value.tool === "calculate" || value.tool === "matrix" || value.tool === "solver" || value.tool === "numerical") &&
    typeof value.title === "string" &&
    typeof value.detail === "string" &&
    typeof value.value === "string" &&
    typeof value.createdAt === "string" &&
    isHistoryModeMetadata(value.mode)
  );
}

function isMemoryRegister(value: unknown): value is MemoryRegister {
  return (
    isRecord(value) &&
    typeof value.id === "string" &&
    typeof value.label === "string" &&
    typeof value.value === "string" &&
    typeof value.detail === "string" &&
    (value.sourceTool === null ||
      value.sourceTool === "calculate" ||
      value.sourceTool === "matrix" ||
      value.sourceTool === "solver" ||
      value.sourceTool === "numerical") &&
    (value.updatedAt === null || typeof value.updatedAt === "string") &&
    (value.mode === null || isHistoryModeMetadata(value.mode))
  );
}

function isWorkspaceState(value: unknown): value is WorkspaceState {
  if (!isRecord(value) || !isRecord(value.matrix) || !isRecord(value.solver) || !isRecord(value.numerical)) {
    return false;
  }

  return (
    (value.activeTool === "calculate" ||
      value.activeTool === "matrix" ||
      value.activeTool === "solver" ||
      value.activeTool === "numerical") &&
    typeof value.expressionInput === "string" &&
    isMatrixData(value.matrix.left) &&
    (!("right" in value.matrix) || value.matrix.right === undefined || isMatrixData(value.matrix.right)) &&
    typeof value.solver.expression === "string" &&
    (value.solver.method === "newton" || value.solver.method === "bisection") &&
    typeof value.solver.initialGuess === "string" &&
    typeof value.solver.bracketLower === "string" &&
    typeof value.solver.bracketUpper === "string" &&
    typeof value.numerical.expression === "string" &&
    (value.numerical.tool === "differentiate" ||
      value.numerical.tool === "integrate" ||
      value.numerical.tool === "sample") &&
    (value.numerical.differentiationMethod === "central" ||
      value.numerical.differentiationMethod === "five-point") &&
    (value.numerical.integrationMethod === "trapezoidal" ||
      value.numerical.integrationMethod === "simpson") &&
    typeof value.numerical.point === "string" &&
    typeof value.numerical.intervalStart === "string" &&
    typeof value.numerical.intervalEnd === "string"
  );
}

export function parsePersistedSettings(value: unknown): PersistedSettingsDocument | null {
  if (!isRecord(value) || value.version !== SETTINGS_SCHEMA_VERSION || !isCalculatorSettings(value.payload)) {
    return null;
  }

  return {
    version: SETTINGS_SCHEMA_VERSION,
    updatedAt: typeof value.updatedAt === "string" ? value.updatedAt : DEFAULT_UPDATED_AT,
    payload: sanitizeCalculatorSettings(value.payload)
  };
}

export function parsePersistedWorkspace(value: unknown): PersistedWorkspaceDocument | null {
  if (!isRecord(value) || value.version !== WORKSPACE_SCHEMA_VERSION || !isWorkspaceState(value.payload)) {
    return null;
  }

  return {
    version: WORKSPACE_SCHEMA_VERSION,
    updatedAt: typeof value.updatedAt === "string" ? value.updatedAt : DEFAULT_UPDATED_AT,
    payload: sanitizeWorkspaceState(value.payload)
  };
}

export function parsePersistedHistory(value: unknown): PersistedHistoryDocument | null {
  if (
    !isRecord(value) ||
    value.version !== HISTORY_SCHEMA_VERSION ||
    !isRecord(value.payload) ||
    !Array.isArray(value.payload.entries) ||
    !value.payload.entries.every((entry) => isHistoryEntry(entry))
  ) {
    return null;
  }

  return {
    version: HISTORY_SCHEMA_VERSION,
    updatedAt: typeof value.updatedAt === "string" ? value.updatedAt : DEFAULT_UPDATED_AT,
    payload: {
      entries: value.payload.entries
    }
  };
}

export function parsePersistedMemory(value: unknown): PersistedMemoryDocument | null {
  if (
    !isRecord(value) ||
    value.version !== MEMORY_SCHEMA_VERSION ||
    !isRecord(value.payload) ||
    !Array.isArray(value.payload.registers) ||
    !value.payload.registers.every((register) => isMemoryRegister(register))
  ) {
    return null;
  }

  return {
    version: MEMORY_SCHEMA_VERSION,
    updatedAt: typeof value.updatedAt === "string" ? value.updatedAt : DEFAULT_UPDATED_AT,
    payload: {
      registers: value.payload.registers
    }
  };
}

import type { ReactNode } from "react";
import type { ComputationIssue } from "@core/contracts";

interface MetadataItem {
  label: string;
  value: string;
}

interface ResultPanelProps {
  eyebrow: string;
  title: string;
  value: string;
  detail: string;
  issues: ComputationIssue[];
  metadata: MetadataItem[];
  children?: ReactNode;
}

export function ResultPanel({ eyebrow, title, value, detail, issues, metadata, children }: ResultPanelProps) {
  return (
    <section className="panel result-panel">
      <header className="panel-header">
        <div>
          <p className="eyebrow">{eyebrow}</p>
          <h2>{title}</h2>
        </div>
        <span>{issues.length === 0 ? "ready" : `${issues.length} alert${issues.length === 1 ? "" : "s"}`}</span>
      </header>
      <div className="result-value">{value}</div>
      <p className="result-detail">{detail}</p>
      <dl className="meta-grid">
        {metadata.map((item) => (
          <div key={item.label}>
            <dt>{item.label}</dt>
            <dd>{item.value}</dd>
          </div>
        ))}
      </dl>
      {issues.length > 0 ? (
        <ul className="issue-list">
          {issues.map((issue) => (
            <li key={issue.code}>
              <strong>{issue.severity}</strong>
              <span>{issue.message}</span>
            </li>
          ))}
        </ul>
      ) : null}
      {children ? <div className="result-actions">{children}</div> : null}
    </section>
  );
}

import type {
  CalculatorSettings,
  ComputationIssue,
  LinearSystemRequest,
  MatrixData,
  MatrixOperationRequest,
  MatrixService,
  ResultEnvelope
} from "@core/contracts";
import {
  MAX_MATRIX_SIZE,
  MatrixComputationError,
  addMatrices,
  determinant,
  invertMatrix,
  multiplyMatrices,
  solveLinearSystem,
  subtractMatrices,
  transposeMatrix
} from "@core/matrix";

const MIN_MATRIX_SIZE = 2;

export function createMatrixService(): MatrixService {
  return {
    evaluate(request) {
      try {
        validateUiMatrixBounds(request.left, "left");
        if (request.right) {
          validateUiMatrixBounds(request.right, "right");
        }

        switch (request.operation) {
          case "add":
            return succeed(
              request.settings,
              {
                operation: request.operation,
                matrix: addMatrices(request.left, requireRightMatrix(request.right))
              },
              []
            );
          case "subtract":
            return succeed(
              request.settings,
              {
                operation: request.operation,
                matrix: subtractMatrices(request.left, requireRightMatrix(request.right))
              },
              []
            );
          case "multiply":
            return succeed(
              request.settings,
              {
                operation: request.operation,
                matrix: multiplyMatrices(request.left, requireRightMatrix(request.right))
              },
              []
            );
          case "transpose":
            return succeed(
              request.settings,
              {
                operation: request.operation,
                matrix: transposeMatrix(request.left),
                diagnostics: {
                  pivotStrategy: "none",
                  singular: false
                }
              },
              []
            );
          case "determinant": {
            const result = determinant(request.left, { tolerance: request.settings.numeric.solverTolerance });
            return succeed(
              request.settings,
              {
                operation: request.operation,
                scalar: formatNumber(result.value, request.settings),
                diagnostics: result.diagnostics
              },
              buildConditionIssues(result.diagnostics.conditionEstimate)
            );
          }
          case "inverse": {
            const result = invertMatrix(request.left, { tolerance: request.settings.numeric.solverTolerance });
            return succeed(
              request.settings,
              {
                operation: request.operation,
                matrix: result.matrix,
                diagnostics: result.diagnostics
              },
              buildConditionIssues(result.diagnostics.conditionEstimate)
            );
          }
          default:
            return fail(request.settings, [
              {
                code: "matrix_operation_unsupported",
                message: `Unsupported matrix operation: ${String(request.operation)}`,
                severity: "error",
                field: "operation"
              }
            ]);
        }
      } catch (error) {
        return fail(request.settings, [toIssue(error)]);
      }
    },
    solveLinearSystem(request) {
      try {
        validateUiMatrixBounds(request.matrix, "matrix");
        const result = solveLinearSystem(request.matrix, request.rightHandSide, {
          tolerance: request.settings.numeric.solverTolerance
        });

        return succeed(
          request.settings,
          {
            solution: result.solution,
            residualNorm: result.residualNorm,
            diagnostics: result.diagnostics
          },
          buildConditionIssues(result.diagnostics.conditionEstimate)
        );
      } catch (error) {
        return fail(request.settings, [toIssue(error)]);
      }
    }
  };
}

function requireRightMatrix(matrix: MatrixData | undefined): MatrixData {
  if (!matrix) {
    throw new MatrixComputationError(
      "matrix_missing_operand",
      "This matrix operation requires a right-hand matrix.",
      "right"
    );
  }

  return matrix;
}

function validateUiMatrixBounds(matrix: MatrixData, fieldPrefix: string): void {
  if (matrix.rows < MIN_MATRIX_SIZE || matrix.rows > MAX_MATRIX_SIZE) {
    throw new MatrixComputationError(
      "matrix_size_out_of_range",
      `Matrix row count must stay within ${MIN_MATRIX_SIZE}x${MIN_MATRIX_SIZE} through ${MAX_MATRIX_SIZE}x${MAX_MATRIX_SIZE} work.`,
      `${fieldPrefix}.rows`
    );
  }

  if (matrix.columns < MIN_MATRIX_SIZE || matrix.columns > MAX_MATRIX_SIZE) {
    throw new MatrixComputationError(
      "matrix_size_out_of_range",
      `Matrix column count must stay within ${MIN_MATRIX_SIZE}x${MIN_MATRIX_SIZE} through ${MAX_MATRIX_SIZE}x${MAX_MATRIX_SIZE} work.`,
      `${fieldPrefix}.columns`
    );
  }
}

function succeed<T>(
  settings: CalculatorSettings,
  value: T,
  issues: ComputationIssue[]
): ResultEnvelope<T> {
  return {
    ok: true,
    value,
    issues,
    metadata: {
      backend: settings.numeric.backend
    }
  };
}

function fail<T>(settings: CalculatorSettings, issues: ComputationIssue[]): ResultEnvelope<T> {
  return {
    ok: false,
    issues,
    metadata: {
      backend: settings.numeric.backend
    }
  };
}

function toIssue(error: unknown): ComputationIssue {
  if (error instanceof MatrixComputationError) {
    const issue: ComputationIssue = {
      code: error.code,
      message: error.message,
      severity: "error"
    };
    if (error.field !== undefined) {
      issue.field = error.field;
    }
    return issue;
  }

  return {
    code: "matrix_unknown_error",
    message: error instanceof Error ? error.message : "Unknown matrix error.",
    severity: "error"
  };
}

function buildConditionIssues(conditionEstimate: number | undefined): ComputationIssue[] {
  if (conditionEstimate === undefined || conditionEstimate < 1e8) {
    return [];
  }

  return [
    {
      code: "matrix_ill_conditioned",
      message: "Matrix appears ill-conditioned; small input changes may cause large output changes.",
      severity: "warning",
      field: "left"
    }
  ];
}

function formatNumber(value: number, settings: CalculatorSettings): string {
  const precision = Math.min(15, Math.max(2, Math.trunc(settings.numeric.displayPrecision)));
  const normalized = normalizeNegativeZero(value);

  if (normalized === 0) {
    return "0";
  }

  switch (settings.numeric.displayMode) {
    case "scientific":
      return normalized.toExponential(precision - 1);
    case "engineering":
      return formatEngineering(normalized, precision);
    case "normal":
    default:
      return Number.parseFloat(normalized.toPrecision(precision)).toString();
  }
}

function formatEngineering(value: number, precision: number): string {
  const exponent = Math.floor(Math.log10(Math.abs(value)) / 3) * 3;
  const mantissa = value / 10 ** exponent;
  return `${mantissa.toPrecision(precision)}e${exponent >= 0 ? "+" : ""}${exponent}`;
}

function normalizeNegativeZero(value: number): number {
  return Object.is(value, -0) ? 0 : value;
}

import type { ConditionDiagnostics, MatrixData } from "@core/contracts";

export const MAX_MATRIX_SIZE = 6;

export interface MatrixEngineOptions {
  tolerance?: number;
}

export interface MatrixScalarComputation {
  value: number;
  diagnostics: ConditionDiagnostics;
}

export interface MatrixComputation {
  matrix: MatrixData;
  diagnostics: ConditionDiagnostics;
}

export interface LinearSolveComputation {
  solution: number[];
  residualNorm: number;
  diagnostics: ConditionDiagnostics;
}

export class MatrixComputationError extends Error {
  readonly code: string;
  readonly field: string | undefined;

  constructor(code: string, message: string, field?: string) {
    super(message);
    this.name = "MatrixComputationError";
    this.code = code;
    this.field = field;
  }
}

interface Decomposition {
  lu: number[][];
  permutation: number[];
  swapCount: number;
  threshold: number;
  normInfinity: number;
}

export function addMatrices(left: MatrixData, right: MatrixData): MatrixData {
  const leftValues = toValidatedValues(left, "left");
  const rightValues = toValidatedValues(right, "right");
  ensureMatchingDimensions(left, right, "matrix_dimension_mismatch", "Matrix addition requires matching dimensions.");

  return fromValues(
    leftValues.map((row, rowIndex) =>
      row.map((value, columnIndex) => value + rightValues[rowIndex]![columnIndex]!)
    )
  );
}

export function subtractMatrices(left: MatrixData, right: MatrixData): MatrixData {
  const leftValues = toValidatedValues(left, "left");
  const rightValues = toValidatedValues(right, "right");
  ensureMatchingDimensions(left, right, "matrix_dimension_mismatch", "Matrix subtraction requires matching dimensions.");

  return fromValues(
    leftValues.map((row, rowIndex) =>
      row.map((value, columnIndex) => value - rightValues[rowIndex]![columnIndex]!)
    )
  );
}

export function multiplyMatrices(left: MatrixData, right: MatrixData): MatrixData {
  const leftValues = toValidatedValues(left, "left");
  const rightValues = toValidatedValues(right, "right");

  if (left.columns !== right.rows) {
    throw new MatrixComputationError(
      "matrix_dimension_mismatch",
      "Matrix multiplication requires the left column count to match the right row count.",
      "right.rows"
    );
  }

  const values = Array.from({ length: left.rows }, (_, rowIndex) =>
    Array.from({ length: right.columns }, (_, columnIndex) => {
      let sum = 0;
      for (let innerIndex = 0; innerIndex < left.columns; innerIndex += 1) {
        sum += leftValues[rowIndex]![innerIndex]! * rightValues[innerIndex]![columnIndex]!;
      }
      return sum;
    })
  );

  return fromValues(values);
}

export function transposeMatrix(matrix: MatrixData): MatrixData {
  const values = toValidatedValues(matrix, "left");

  return fromValues(
    Array.from({ length: matrix.columns }, (_, columnIndex) =>
      Array.from({ length: matrix.rows }, (_, rowIndex) => values[rowIndex]![columnIndex]!)
    )
  );
}

export function determinant(matrix: MatrixData, options: MatrixEngineOptions = {}): MatrixScalarComputation {
  const values = toValidatedValues(matrix, "left");
  ensureSquare(matrix, "Determinant requires a square matrix.");

  const decomposition = decomposeWithPartialPivoting(values, options);
  let value = decomposition.swapCount % 2 === 0 ? 1 : -1;
  for (let index = 0; index < matrix.rows; index += 1) {
    value *= decomposition.lu[index]![index]!;
  }

  return {
    value,
    diagnostics: {
      pivotStrategy: "partial",
      singular: false,
      conditionEstimate: estimateConditionNumberFromDecomposition(decomposition)
    }
  };
}

export function invertMatrix(matrix: MatrixData, options: MatrixEngineOptions = {}): MatrixComputation {
  const values = toValidatedValues(matrix, "left");
  ensureSquare(matrix, "Matrix inversion requires a square matrix.");

  const decomposition = decomposeWithPartialPivoting(values, options);
  const inverseValues = invertFromDecomposition(decomposition);

  return {
    matrix: fromValues(inverseValues),
    diagnostics: {
      pivotStrategy: "partial",
      singular: false,
      conditionEstimate: normInfinity(values) * normInfinity(inverseValues)
    }
  };
}

export function solveLinearSystem(
  matrix: MatrixData,
  rightHandSide: number[],
  options: MatrixEngineOptions = {}
): LinearSolveComputation {
  const values = toValidatedValues(matrix, "matrix");
  ensureSquare(matrix, "Linear solve requires a square coefficient matrix.");

  if (rightHandSide.length !== matrix.rows) {
    throw new MatrixComputationError(
      "matrix_dimension_mismatch",
      "Linear solve requires one right-hand-side entry per matrix row.",
      "rightHandSide"
    );
  }

  const sanitizedRightHandSide = rightHandSide.map((value, index) => {
    if (!Number.isFinite(value)) {
      throw new MatrixComputationError(
        "matrix_invalid_value",
        "Right-hand-side values must be finite numbers.",
        `rightHandSide[${index}]`
      );
    }
    return value;
  });

  const decomposition = decomposeWithPartialPivoting(values, options);
  const solution = solveFromDecomposition(decomposition, sanitizedRightHandSide);
  const residualNorm = vectorInfinityNorm(subtractVectors(multiplyMatrixVector(values, solution), sanitizedRightHandSide));

  return {
    solution,
    residualNorm,
    diagnostics: {
      pivotStrategy: "partial",
      singular: false,
      conditionEstimate: estimateConditionNumberFromDecomposition(decomposition)
    }
  };
}

function toValidatedValues(matrix: MatrixData, fieldPrefix: string): number[][] {
  if (!Number.isInteger(matrix.rows) || matrix.rows < 1 || matrix.rows > MAX_MATRIX_SIZE) {
    throw new MatrixComputationError(
      "matrix_size_out_of_range",
      `Matrix row count must be between 1 and ${MAX_MATRIX_SIZE}.`,
      `${fieldPrefix}.rows`
    );
  }

  if (!Number.isInteger(matrix.columns) || matrix.columns < 1 || matrix.columns > MAX_MATRIX_SIZE) {
    throw new MatrixComputationError(
      "matrix_size_out_of_range",
      `Matrix column count must be between 1 and ${MAX_MATRIX_SIZE}.`,
      `${fieldPrefix}.columns`
    );
  }

  if (matrix.values.length !== matrix.rows) {
    throw new MatrixComputationError(
      "matrix_shape_mismatch",
      "Matrix row metadata does not match the provided values.",
      `${fieldPrefix}.values`
    );
  }

  return matrix.values.map((row, rowIndex) => {
    if (row.length !== matrix.columns) {
      throw new MatrixComputationError(
        "matrix_shape_mismatch",
        "Matrix column metadata does not match the provided values.",
        `${fieldPrefix}.values[${rowIndex}]`
      );
    }

    return row.map((value, columnIndex) => {
      if (!Number.isFinite(value)) {
        throw new MatrixComputationError(
          "matrix_invalid_value",
          "Matrix entries must be finite numbers.",
          `${fieldPrefix}.values[${rowIndex}][${columnIndex}]`
        );
      }

      return value;
    });
  });
}

function ensureMatchingDimensions(
  left: MatrixData,
  right: MatrixData,
  code: string,
  message: string
): void {
  if (left.rows !== right.rows || left.columns !== right.columns) {
    throw new MatrixComputationError(code, message, "right");
  }
}

function ensureSquare(matrix: MatrixData, message: string): void {
  if (matrix.rows !== matrix.columns) {
    throw new MatrixComputationError("matrix_not_square", message, "left");
  }
}

function decomposeWithPartialPivoting(values: number[][], options: MatrixEngineOptions): Decomposition {
  const size = values.length;
  const lu = cloneValues(values);
  const permutation = Array.from({ length: size }, (_, index) => index);
  const matrixNorm = normInfinity(values);
  const requestedTolerance = Math.abs(options.tolerance ?? 1e-10);
  const threshold = Math.max(
    requestedTolerance * Math.max(1, matrixNorm),
    Number.EPSILON * Math.max(1, matrixNorm) * size * 16
  );
  let swapCount = 0;

  for (let pivotColumn = 0; pivotColumn < size; pivotColumn += 1) {
    let pivotRow = pivotColumn;
    let pivotMagnitude = Math.abs(lu[pivotColumn]![pivotColumn]!);

    for (let row = pivotColumn + 1; row < size; row += 1) {
      const candidate = Math.abs(lu[row]![pivotColumn]!);
      if (candidate > pivotMagnitude) {
        pivotMagnitude = candidate;
        pivotRow = row;
      }
    }

    if (pivotMagnitude <= threshold) {
      throw new MatrixComputationError(
        "matrix_singular",
        "Matrix is singular to the configured tolerance; determinant, inverse, or solve cannot proceed.",
        "left"
      );
    }

    if (pivotRow !== pivotColumn) {
      const pivotValues = lu[pivotColumn]!;
      lu[pivotColumn] = lu[pivotRow]!;
      lu[pivotRow] = pivotValues;

      const pivotIndex = permutation[pivotColumn]!;
      permutation[pivotColumn] = permutation[pivotRow]!;
      permutation[pivotRow] = pivotIndex;
      swapCount += 1;
    }

    for (let row = pivotColumn + 1; row < size; row += 1) {
      lu[row]![pivotColumn]! /= lu[pivotColumn]![pivotColumn]!;
      for (let column = pivotColumn + 1; column < size; column += 1) {
        lu[row]![column]! -= lu[row]![pivotColumn]! * lu[pivotColumn]![column]!;
      }
    }
  }

  return {
    lu,
    permutation,
    swapCount,
    threshold,
    normInfinity: matrixNorm
  };
}

function solveFromDecomposition(decomposition: Decomposition, rightHandSide: number[]): number[] {
  const size = decomposition.lu.length;
  const permuted = Array.from({ length: size }, (_, index) => rightHandSide[decomposition.permutation[index]!]!);
  const intermediate = Array.from({ length: size }, () => 0);
  const solution = Array.from({ length: size }, () => 0);

  for (let row = 0; row < size; row += 1) {
    let value = permuted[row]!;
    for (let column = 0; column < row; column += 1) {
      value -= decomposition.lu[row]![column]! * intermediate[column]!;
    }
    intermediate[row] = value;
  }

  for (let row = size - 1; row >= 0; row -= 1) {
    let value = intermediate[row]!;
    for (let column = row + 1; column < size; column += 1) {
      value -= decomposition.lu[row]![column]! * solution[column]!;
    }

    const pivot = decomposition.lu[row]![row]!;
    if (Math.abs(pivot) <= decomposition.threshold) {
      throw new MatrixComputationError(
        "matrix_singular",
        "Matrix is singular to the configured tolerance; determinant, inverse, or solve cannot proceed.",
        "left"
      );
    }

    solution[row] = value / pivot;
  }

  return solution;
}

function invertFromDecomposition(decomposition: Decomposition): number[][] {
  const size = decomposition.lu.length;
  const inverse = Array.from({ length: size }, () => Array.from({ length: size }, () => 0));

  for (let column = 0; column < size; column += 1) {
    const basis = Array.from({ length: size }, (_, index) => (index === column ? 1 : 0));
    const solution = solveFromDecomposition(decomposition, basis);
    for (let row = 0; row < size; row += 1) {
      inverse[row]![column] = solution[row]!;
    }
  }

  return inverse;
}

function estimateConditionNumberFromDecomposition(decomposition: Decomposition): number {
  const inverse = invertFromDecomposition(decomposition);
  return decomposition.normInfinity * normInfinity(inverse);
}

function cloneValues(values: number[][]): number[][] {
  return values.map((row) => [...row]);
}

function fromValues(values: number[][]): MatrixData {
  return {
    rows: values.length,
    columns: values[0]?.length ?? 0,
    values: cloneValues(values)
  };
}

function normInfinity(values: number[][]): number {
  return values.reduce((maximum, row) => {
    const rowSum = row.reduce((sum, value) => sum + Math.abs(value), 0);
    return Math.max(maximum, rowSum);
  }, 0);
}

function vectorInfinityNorm(values: number[]): number {
  return values.reduce((maximum, value) => Math.max(maximum, Math.abs(value)), 0);
}

function multiplyMatrixVector(values: number[][], vector: number[]): number[] {
  return values.map((row) => row.reduce((sum, value, columnIndex) => sum + value * vector[columnIndex]!, 0));
}

function subtractVectors(left: number[], right: number[]): number[] {
  return left.map((value, index) => value - right[index]!);
}

