                  <span>{entry.mode.displayMode}</span>
                  <span>{entry.mode.displayPrecision} digits</span>
                </div>
              </article>
            ))}
          </div>
        )}
      </section>
    </main>
  );
}

function buildNumericalRequest(
  draft: NumericalDraft,
  settings: CalculatorSettings
): { ok: true; value: NumericalRequest } | { ok: false; issues: ComputationIssue[] } {
  const tool = draft.tool === "integrate" ? "integrate" : "differentiate";

  if (tool === "differentiate") {
    const point = Number(draft.point);
    if (!Number.isFinite(point)) {
      return {
        ok: false,
        issues: [
          {
            code: "numerical.invalid_point",
            message: "Enter a finite point for differentiation.",
            severity: "error",
            field: "point"
          }
        ]
      };
    }

    return {
      ok: true,
      value: {
        tool,
        expression: draft.expression,
        settings,
        point,
        differentiationMethod: draft.differentiationMethod
      }
    };
  }

  const start = Number(draft.intervalStart);
  const end = Number(draft.intervalEnd);
  if (!Number.isFinite(start) || !Number.isFinite(end)) {
    return {
      ok: false,
      issues: [
        {
          code: "numerical.invalid_interval",
          message: "Enter finite interval bounds for integration.",
          severity: "error",
          field: "interval"
        }
      ]
    };
  }

  return {
    ok: true,
    value: {
      tool,
      expression: draft.expression,
      settings,
      interval: [start, end],
      integrationMethod: draft.integrationMethod
    }
  };
}

function failEnvelope<T>(
  settings: CalculatorSettings,
  issues: ComputationIssue[]
): ResultEnvelope<T> {
  return {
    ok: false,
    issues,
    metadata: {
      backend: settings.numeric.backend
    }
  };
}

function labelNumericalMethod(method: NumericalResult["method"]): string {
  switch (method) {
    case "central":
      return "Central difference";
    case "five-point":
      return "Five-point stencil";
    case "trapezoidal":
      return "Trapezoidal";
    case "simpson":
      return "Simpson";
  }
}

function labelMatrixTitle(operation: MatrixOperationResult["operation"]): string {
  switch (operation) {
    case "add":
      return "Matrix Addition";
    case "subtract":
      return "Matrix Subtraction";
    case "multiply":
      return "Matrix Product";
    case "transpose":
      return "Matrix Transpose";
    case "determinant":
      return "Matrix Determinant";
    case "inverse":
      return "Matrix Inverse";
  }
}

function formatMatrixSummary(matrix: MatrixData | undefined, precision: number): string | null {
  if (!matrix) {
    return null;
  }

  return matrix.values
    .map((row) => `[${row.map((value) => formatCompactNumber(value, precision)).join(", ")}]`)
    .join(" ");
}

function formatVectorSummary(values: number[], precision: number): string {
  return values.map((value, index) => `x${index + 1} = ${formatCompactNumber(value, precision)}`).join(", ");
}

function formatOptionalCompact(value: number | undefined, precision: number): string {
  return value === undefined ? "n/a" : formatCompactNumber(value, precision);
}

function formatCompactNumber(value: number, precision: number): string {
  if (!Number.isFinite(value)) {
    return String(value);
  }

  const normalized = Object.is(value, -0) ? 0 : value;
  if (normalized === 0) {
    return "0";
  }

  return Number.parseFloat(normalized.toPrecision(Math.min(Math.max(precision, 2), 12))).toString();
}

import { useEffect, useState, type Dispatch, type SetStateAction } from "react";
import type {
  CalculatorSettings,
  ComputationIssue,
  LinearSystemResult,
  MatrixData,
  MatrixDraft,
  MatrixOperation,
  MatrixOperationResult,
  ResultEnvelope
} from "@core/contracts";
import { MAX_MATRIX_SIZE } from "@core/matrix";
import { createDefaultWorkspaceState } from "../../app/workspaceDrafts";
import { createMatrixService } from "../../services/matrix";

type MatrixAction = MatrixOperation | "solve";

interface MatrixWorkbenchProps {
  settings: CalculatorSettings;
  draft: MatrixDraft;
  result: ResultEnvelope<MatrixOperationResult | LinearSystemResult> | null;
  onDraftChange(recipe: (current: MatrixDraft) => MatrixDraft): void;
  onResultChange: Dispatch<SetStateAction<ResultEnvelope<MatrixOperationResult | LinearSystemResult> | null>>;
}

const matrixService = createMatrixService();
const defaultDraft = createDefaultWorkspaceState().matrix;

const actionLabels: Record<MatrixAction, string> = {
  add: "Add",
  subtract: "Subtract",
  multiply: "Multiply",
  transpose: "Transpose",
  determinant: "Determinant",
  inverse: "Inverse",
  solve: "Solve Ax = b"
};

const binaryActions: MatrixAction[] = ["add", "subtract", "multiply"];

export function MatrixWorkbench({
  settings,
  draft,
  result,
  onDraftChange,
  onResultChange
}: MatrixWorkbenchProps) {
  const [action, setAction] = useState<MatrixAction>("solve");
  const [leftSize, setLeftSize] = useState({ rows: draft.left.rows, columns: draft.left.columns });
  const [rightSize, setRightSize] = useState({
    rows: draft.right?.rows ?? draft.left.rows,
    columns: draft.right?.columns ?? draft.left.columns
  });
  const [leftValues, setLeftValues] = useState(() => toDraftValues(draft.left));
  const [rightValues, setRightValues] = useState(() => toDraftValues(draft.right ?? draft.left));
  const [rightHandSide, setRightHandSide] = useState(() => createVectorDraft(draft.left.rows));

  const usesRightMatrix = binaryActions.includes(action);
  const usesRightHandSide = action === "solve";

  useEffect(() => {
    setLeftSize({ rows: draft.left.rows, columns: draft.left.columns });
    setRightSize({
      rows: draft.right?.rows ?? draft.left.rows,
      columns: draft.right?.columns ?? draft.left.columns
    });
    setLeftValues(toDraftValues(draft.left));
    setRightValues(toDraftValues(draft.right ?? draft.left));
  }, [draft]);

  useEffect(() => {
    onResultChange(null);
  }, [action, leftSize, leftValues, onResultChange, rightHandSide, rightSize, rightValues, settings]);

  function updateLeftSize(nextRows: number, nextColumns: number) {
    const nextValues = resizeDraftMatrix(leftValues, nextRows, nextColumns);
    setLeftSize({ rows: nextRows, columns: nextColumns });
    setLeftValues(nextValues);
    setRightHandSide((current) => resizeDraftVector(current, nextRows));
    onDraftChange((current) => ({
      ...current,
      left: toPersistedMatrix(nextValues, nextRows, nextColumns)
    }));
  }

  function updateRightSize(nextRows: number, nextColumns: number) {
    const nextValues = resizeDraftMatrix(rightValues, nextRows, nextColumns);
    setRightSize({ rows: nextRows, columns: nextColumns });
    setRightValues(nextValues);
    onDraftChange((current) => ({
      ...current,
      right: toPersistedMatrix(nextValues, nextRows, nextColumns)
    }));
  }

  function submit() {
    if (action === "solve") {
      const coefficientMatrix = parseMatrixDraft(leftValues, leftSize.rows, leftSize.columns);
      const vector = parseVectorDraft(rightHandSide, leftSize.rows);

      if (!coefficientMatrix.ok) {
        onResultChange(failEnvelope(settings, [coefficientMatrix.issue]));
        return;
      }

      if (!vector.ok) {
        onResultChange(failEnvelope(settings, [vector.issue]));
        return;
      }

      const startedAt = nowMs();
      void Promise.resolve(
        matrixService.solveLinearSystem({
          matrix: coefficientMatrix.value,
          rightHandSide: vector.value,
          settings
        })
      ).then((response) => onResultChange(withElapsedMetadata(response, startedAt)));
      return;
    }

    const leftMatrix = parseMatrixDraft(leftValues, leftSize.rows, leftSize.columns);
    if (!leftMatrix.ok) {
      onResultChange(failEnvelope(settings, [leftMatrix.issue]));
      return;
    }

    const rightMatrix = usesRightMatrix
      ? parseMatrixDraft(rightValues, rightSize.rows, rightSize.columns)
      : null;

    if (rightMatrix !== null && !rightMatrix.ok) {
      onResultChange(failEnvelope(settings, [rightMatrix.issue]));
      return;
    }

    const request =
      rightMatrix !== null
        ? {
            operation: action,
            left: leftMatrix.value,
            right: rightMatrix.value,
            settings
          }
        : {
            operation: action,
            left: leftMatrix.value,
            settings
          };

    const startedAt = nowMs();
    void Promise.resolve(matrixService.evaluate(request)).then((response) =>
      onResultChange(withElapsedMetadata(response, startedAt))
    );
  }

  function resetDrafts() {
    setAction("solve");
    setLeftSize({ rows: defaultDraft.left.rows, columns: defaultDraft.left.columns });
    setRightSize({
      rows: defaultDraft.right?.rows ?? defaultDraft.left.rows,
      columns: defaultDraft.right?.columns ?? defaultDraft.left.columns
    });
    setLeftValues(toDraftValues(defaultDraft.left));
    setRightValues(toDraftValues(defaultDraft.right ?? defaultDraft.left));
    setRightHandSide(createVectorDraft(defaultDraft.left.rows));
    onDraftChange(() => defaultDraft);
    onResultChange(null);
  }

  return (
    <section className="matrix-workbench">
      <header className="matrix-toolbar">
        <div>
          <p className="eyebrow">Matrix mode</p>
          <h3>Stable linear algebra workspace</h3>
          <p className="matrix-caption">
            Partial pivoting is used for determinant, inverse, and linear solve. Matrix sizes are limited to
            2 through {MAX_MATRIX_SIZE} per dimension in this workflow.
          </p>
        </div>
        <div className="matrix-toolbar-actions">
          <label className="field-stack">
            <span>Action</span>
            <select value={action} onChange={(event) => setAction(event.target.value as MatrixAction)}>
              {(Object.keys(actionLabels) as MatrixAction[]).map((candidate) => (
                <option key={candidate} value={candidate}>
                  {actionLabels[candidate]}
                </option>
              ))}
            </select>
          </label>
          <button type="button" className="secondary-button" onClick={resetDrafts}>
            Reset drafts
          </button>
          <button type="button" className="primary-button" onClick={submit}>
            Run matrix task
          </button>
        </div>
      </header>

      <div className="matrix-meta-strip">
        <span>Backend: {settings.numeric.backend}</span>
        <span>Tolerance: {formatCompact(settings.numeric.solverTolerance)}</span>
        <span>Display: {settings.numeric.displayMode}</span>
        <span>Precision: {settings.numeric.displayPrecision} digits</span>
      </div>

      <div className="matrix-pane-grid">
        <MatrixEditor
          title="Left matrix A"
          size={leftSize}
          values={leftValues}
          onSizeChange={updateLeftSize}
          onValuesChange={(nextValues) => {
            setLeftValues(nextValues);
            const nextMatrix = toPersistedMatrixOrNull(nextValues, leftSize.rows, leftSize.columns);
            if (nextMatrix) {
              onDraftChange((current) => ({
                ...current,
                left: nextMatrix
              }));
            }
          }}
        />

        {usesRightMatrix ? (
          <MatrixEditor
            title="Right matrix B"
            size={rightSize}
            values={rightValues}
            onSizeChange={updateRightSize}
            onValuesChange={(nextValues) => {
              setRightValues(nextValues);
              const nextMatrix = toPersistedMatrixOrNull(nextValues, rightSize.rows, rightSize.columns);
              if (nextMatrix) {
                onDraftChange((current) => ({
                  ...current,
                  right: nextMatrix
                }));
              }
            }}
          />
        ) : usesRightHandSide ? (
          <VectorEditor values={rightHandSide} onValuesChange={setRightHandSide} />
        ) : (
          <article className="matrix-pane matrix-note-pane">
            <h4>Unary operation</h4>
            <p className="matrix-caption">
              This action only uses matrix A. The result panel shows the transformed matrix or scalar output
              together with singularity and conditioning diagnostics when relevant.
            </p>
          </article>
        )}
      </div>

      <ResultPanel result={result} settings={settings} />
    </section>
  );
}

interface MatrixEditorProps {
  title: string;
  size: {
    rows: number;
    columns: number;
  };
  values: string[][];
  onSizeChange: (rows: number, columns: number) => void;
  onValuesChange: (values: string[][]) => void;
}

function MatrixEditor({ title, size, values, onSizeChange, onValuesChange }: MatrixEditorProps) {
  return (
    <article className="matrix-pane">
      <header className="matrix-pane-header">
        <h4>{title}</h4>
        <div className="matrix-dimension-controls">
          <label className="field-stack">
            <span>Rows</span>
            <select
              value={size.rows}
              onChange={(event) => onSizeChange(Number(event.target.value), size.columns)}
            >
              {dimensionOptions()}
            </select>
          </label>
          <label className="field-stack">
            <span>Columns</span>
            <select
              value={size.columns}
              onChange={(event) => onSizeChange(size.rows, Number(event.target.value))}
            >
              {dimensionOptions()}
            </select>
          </label>
        </div>
      </header>
      <div
        className="matrix-grid"
        style={{ gridTemplateColumns: `repeat(${size.columns}, minmax(0, 1fr))` }}
      >
        {values.map((row, rowIndex) =>
          row.map((value, columnIndex) => (
            <input
              key={`${rowIndex}-${columnIndex}`}
              className="matrix-cell"
              type="text"
              inputMode="decimal"
              value={value}
              onChange={(event) =>
                onValuesChange(
                  values.map((candidateRow, candidateRowIndex) =>
                    candidateRowIndex === rowIndex
                      ? candidateRow.map((candidateValue, candidateColumnIndex) =>
                          candidateColumnIndex === columnIndex ? event.target.value : candidateValue
                        )
                      : candidateRow
                  )
                )
              }
            />
          ))
        )}
      </div>
    </article>
  );
}

interface VectorEditorProps {
  values: string[];
  onValuesChange: (values: string[]) => void;
}

function VectorEditor({ values, onValuesChange }: VectorEditorProps) {
  return (
    <article className="matrix-pane">
      <header className="matrix-pane-header">
        <h4>Right-hand side b</h4>
        <p className="matrix-caption">Enter one entry per row of matrix A.</p>
      </header>
      <div className="vector-grid">
        {values.map((value, index) => (
          <input
            key={index}
            className="matrix-cell"
            type="text"
            inputMode="decimal"
            value={value}
            onChange={(event) =>
              onValuesChange(
                values.map((candidate, candidateIndex) =>
                  candidateIndex === index ? event.target.value : candidate
                )
              )
            }
          />
        ))}
      </div>
    </article>
  );
}

interface ResultPanelProps {
  result: ResultEnvelope<MatrixOperationResult | LinearSystemResult> | null;
  settings: CalculatorSettings;
}

function ResultPanel({ result, settings }: ResultPanelProps) {
  if (!result) {
    return (
      <article className="matrix-result-panel">
        <h4>Result</h4>
        <p className="matrix-caption">Run a matrix task to see outputs, diagnostics, and explicit issues.</p>
      </article>
    );
  }

  return (
    <article className="matrix-result-panel">
      <header className="matrix-pane-header">
        <h4>Result</h4>
        <span className={result.ok ? "status-badge status-ok" : "status-badge status-error"}>
          {result.ok ? "Computed" : "Blocked"}
        </span>
      </header>

      {result.issues.length > 0 ? (
        <div className="issue-stack">
          {result.issues.map((issue) => (
            <div
              key={`${issue.code}-${issue.field ?? "general"}`}
              className={issue.severity === "warning" ? "issue-chip issue-warning" : "issue-chip issue-error"}
            >
              <strong>{issue.code}</strong>
              <span>{issue.message}</span>
            </div>
          ))}
        </div>
      ) : null}

      {result.ok ? (
        <ResultValue value={result.value} settings={settings} />
      ) : (
        <p className="matrix-caption">Fix the flagged input or matrix condition issue and run the task again.</p>
      )}
    </article>
  );
}

function ResultValue({
  value,
  settings
}: {
  value: MatrixOperationResult | LinearSystemResult;
  settings: CalculatorSettings;
}) {
  if ("solution" in value) {
    return (
      <>
        <div className="solution-list">
          {value.solution.map((entry, index) => (
            <div key={index} className="solution-chip">
              <strong>x{index + 1}</strong>
              <span>{formatCompact(entry, settings.numeric.displayPrecision)}</span>
            </div>
          ))}
        </div>
        <DiagnosticsSummary
          residualNorm={value.residualNorm}
          conditionEstimate={value.diagnostics?.conditionEstimate}
          pivotStrategy={value.diagnostics?.pivotStrategy}
        />
      </>
    );
  }

  return (
    <>
      {value.scalar ? <p className="scalar-result">{value.scalar}</p> : null}
      {value.matrix ? <MatrixPreview matrix={value.matrix} precision={settings.numeric.displayPrecision} /> : null}
      <DiagnosticsSummary
        residualNorm={undefined}
        conditionEstimate={value.diagnostics?.conditionEstimate}
        pivotStrategy={value.diagnostics?.pivotStrategy}
      />
    </>
  );
}

function DiagnosticsSummary({
  residualNorm,
  conditionEstimate,
  pivotStrategy
}: {
  residualNorm: number | undefined;
  conditionEstimate: number | undefined;
  pivotStrategy: string | undefined;
}) {
  return (
    <div className="diagnostic-grid">
      <div>
        <dt>Pivoting</dt>
        <dd>{pivotStrategy ?? "n/a"}</dd>
      </div>
      {residualNorm !== undefined ? (
        <div>
          <dt>Residual norm</dt>
          <dd>{formatCompact(residualNorm)}</dd>
        </div>
      ) : null}
      {conditionEstimate !== undefined ? (
        <div>
          <dt>Condition estimate</dt>
          <dd>{formatCompact(conditionEstimate)}</dd>
        </div>
      ) : null}
    </div>
  );
}

function MatrixPreview({ matrix, precision }: { matrix: MatrixData; precision: number }) {
  return (
    <div
      className="matrix-preview-grid"
      style={{ gridTemplateColumns: `repeat(${matrix.columns}, minmax(0, 1fr))` }}
    >
      {matrix.values.flatMap((row, rowIndex) =>
        row.map((value, columnIndex) => (
          <span key={`${rowIndex}-${columnIndex}`} className="matrix-preview-cell">
            {formatCompact(value, precision)}
          </span>
        ))
      )}
    </div>
  );
}

function toDraftValues(matrix: MatrixData): string[][] {
  return matrix.values.map((row) => row.map((value) => value.toString()));
}

function createVectorDraft(size: number): string[] {
  return Array.from({ length: size }, (_, index) => (index === 0 ? "1" : "0"));
}

function resizeDraftMatrix(values: string[][], rows: number, columns: number): string[][] {
  return Array.from({ length: rows }, (_, rowIndex) =>
    Array.from({ length: columns }, (_, columnIndex) => values[rowIndex]?.[columnIndex] ?? "")
  );
}

function resizeDraftVector(values: string[], size: number): string[] {
  return Array.from({ length: size }, (_, index) => values[index] ?? "");
}

function parseMatrixDraft(
  values: string[][],
  rows: number,
  columns: number
): { ok: true; value: MatrixData } | { ok: false; issue: ComputationIssue } {
  try {
    const parsed = values.map((row, rowIndex) =>
      row.map((value, columnIndex) => {
        const normalized = value.trim();
        if (normalized.length === 0) {
          throw {
            code: "matrix_input_required",
            message: "All matrix cells must contain a numeric value.",
            severity: "error",
            field: `values[${rowIndex}][${columnIndex}]`
          } satisfies ComputationIssue;
        }

        const numericValue = Number(normalized);
        if (!Number.isFinite(numericValue)) {
          throw {
            code: "matrix_invalid_value",
            message: "Matrix entries must parse as finite numbers.",
            severity: "error",
            field: `values[${rowIndex}][${columnIndex}]`
          } satisfies ComputationIssue;
        }

        return numericValue;
      })
    );

    return {
      ok: true,
      value: {
        rows,
        columns,
        values: parsed
      }
    };
  } catch (issue) {
    return {
      ok: false,
      issue: issue as ComputationIssue
    };
  }
}

function parseVectorDraft(
  values: string[],
  size: number
): { ok: true; value: number[] } | { ok: false; issue: ComputationIssue } {
  try {
    return {
      ok: true,
      value: values.slice(0, size).map((value, index) => {
        const normalized = value.trim();
        if (normalized.length === 0) {
          throw {
            code: "matrix_input_required",
            message: "All right-hand-side entries must contain a numeric value.",
            severity: "error",
            field: `rightHandSide[${index}]`
          } satisfies ComputationIssue;
        }

        const numericValue = Number(normalized);
        if (!Number.isFinite(numericValue)) {
          throw {
            code: "matrix_invalid_value",
            message: "Right-hand-side entries must parse as finite numbers.",
            severity: "error",
            field: `rightHandSide[${index}]`
          } satisfies ComputationIssue;
        }

        return numericValue;
      })
    };
  } catch (issue) {
    return {
      ok: false,
      issue: issue as ComputationIssue
    };
  }
}

function failEnvelope(
  settings: CalculatorSettings,
  issues: ComputationIssue[]
): ResultEnvelope<MatrixOperationResult | LinearSystemResult> {
  return {
    ok: false,
    issues,
    metadata: {
      backend: settings.numeric.backend
    }
  };
}

function toPersistedMatrix(values: string[][], rows: number, columns: number): MatrixData {
  return {
    rows,
    columns,
    values: values.slice(0, rows).map((row) =>
      Array.from({ length: columns }, (_, columnIndex) => {
        const rawValue = row?.[columnIndex]?.trim() ?? "";
        const parsedValue = Number(rawValue);
        return Number.isFinite(parsedValue) ? parsedValue : 0;
      })
    )
  };
}

function toPersistedMatrixOrNull(values: string[][], rows: number, columns: number): MatrixData | null {
  const parsedValues = values.slice(0, rows).map((row) =>
    Array.from({ length: columns }, (_, columnIndex) => {
      const rawValue = row?.[columnIndex]?.trim() ?? "";
      if (rawValue.length === 0) {
        return null;
      }

      const parsedValue = Number(rawValue);
      return Number.isFinite(parsedValue) ? parsedValue : null;
    })
  );

  if (parsedValues.some((row) => row.some((value) => value === null))) {
    return null;
  }

  return {
    rows,
    columns,
    values: parsedValues as number[][]
  };
}

function nowMs(): number {
  if (typeof performance !== "undefined" && typeof performance.now === "function") {
    return performance.now();
  }

  return Date.now();
}

function withElapsedMetadata<T>(result: ResultEnvelope<T>, startedAt: number): ResultEnvelope<T> {
  return {
    ...result,
    metadata: {
      ...result.metadata,
      elapsedMs: Math.max(0, nowMs() - startedAt)
    }
  };
}

function formatCompact(value: number, precision = 8): string {
  if (!Number.isFinite(value)) {
    return value.toString();
  }

  const normalized = Object.is(value, -0) ? 0 : value;
  if (normalized === 0) {
    return "0";
  }

  return Number.parseFloat(normalized.toPrecision(Math.min(precision, 12))).toString();
}

function dimensionOptions() {
  return Array.from({ length: MAX_MATRIX_SIZE - 1 }, (_, index) => index + 2).map((value) => (
    <option key={value} value={value}>
      {value}
    </option>
  ));
}

import type { AngleMode, CalculatorSettings, DisplayMode, NumericBackend } from "@core/contracts";

export const BACKEND_OPTIONS: NumericBackend[] = ["float64", "decimal"];
export const ANGLE_MODE_OPTIONS: AngleMode[] = ["radian", "degree"];
export const DISPLAY_MODE_OPTIONS: DisplayMode[] = ["normal", "scientific", "engineering"];

export const SETTINGS_LIMITS = {
  displayPrecision: { min: 2, max: 24 },
  internalPrecision: { min: 16, max: 128 },
  solverTolerance: { min: 1e-15, max: 1e-3 },
  maxIterations: { min: 5, max: 1000 }
} as const;

export function createDefaultCalculatorSettings(): CalculatorSettings {
  return {
    numeric: {
      backend: "float64",
      displayPrecision: 12,
      internalPrecision: 28,
      solverTolerance: 1e-10,
      maxIterations: 100,
      angleMode: "radian",
      displayMode: "normal"
    },
    locale: "en-US"
  };
}

export function clampInteger(value: number, minimum: number, maximum: number): number {
  if (!Number.isFinite(value)) {
    return minimum;
  }

  return Math.min(maximum, Math.max(minimum, Math.round(value)));
}

export function clampNumber(value: number, minimum: number, maximum: number): number {
  if (!Number.isFinite(value)) {
    return minimum;
  }

  return Math.min(maximum, Math.max(minimum, value));
}

export function sanitizeCalculatorSettings(settings: CalculatorSettings): CalculatorSettings {
  const defaults = createDefaultCalculatorSettings();

  return {
    locale: settings.locale.trim() || defaults.locale,
    numeric: {
      backend: BACKEND_OPTIONS.includes(settings.numeric.backend) ? settings.numeric.backend : defaults.numeric.backend,
      displayPrecision: clampInteger(
        settings.numeric.displayPrecision,
        SETTINGS_LIMITS.displayPrecision.min,
        SETTINGS_LIMITS.displayPrecision.max
      ),
      internalPrecision: clampInteger(
        settings.numeric.internalPrecision,
        SETTINGS_LIMITS.internalPrecision.min,
        SETTINGS_LIMITS.internalPrecision.max
      ),
      solverTolerance: clampNumber(
        settings.numeric.solverTolerance,
        SETTINGS_LIMITS.solverTolerance.min,
        SETTINGS_LIMITS.solverTolerance.max
      ),
      maxIterations: clampInteger(
        settings.numeric.maxIterations,
        SETTINGS_LIMITS.maxIterations.min,
        SETTINGS_LIMITS.maxIterations.max
      ),
      angleMode: ANGLE_MODE_OPTIONS.includes(settings.numeric.angleMode)
        ? settings.numeric.angleMode
        : defaults.numeric.angleMode,
      displayMode: DISPLAY_MODE_OPTIONS.includes(settings.numeric.displayMode)
        ? settings.numeric.displayMode
        : defaults.numeric.displayMode
    }
  };
}

import type {
  ComputationIssue,
  DifferentiationMethod,
  IntegrationMethod,
  NumericalRequest
} from "@core/contracts";
import type { NumericRuntime } from "@core/precision";
import { prepareExpression } from "@core/expression";
import { toComputationIssue } from "@core/expression/compiler";

const SUPPORTED_NUMERICAL_TOOLS = new Set(["differentiate", "integrate"]);

export interface NumericalEngineResult<TValue> {
  tool: "differentiate" | "integrate";
  method: DifferentiationMethod | IntegrationMethod;
  canonicalExpression: string;
  value: TValue;
  approximateValue: number;
  errorEstimate?: number;
  sampleCount: number;
  stepSize?: number;
}

export type NumericalEngineOutcome<TValue> =
  | {
      ok: true;
      value: NumericalEngineResult<TValue>;
      issues: ComputationIssue[];
    }
  | {
      ok: false;
      issues: ComputationIssue[];
    };

class NumericalComputationError extends Error {
  constructor(
    readonly code: string,
    message: string,
    readonly field = "expression"
  ) {
    super(message);
  }
}

interface CompiledFunction<TValue> {
  canonicalExpression: string;
  evaluateAt(point: number): TValue;
}

export function runNumericalAnalysis<TValue>(
  request: NumericalRequest,
  runtime: NumericRuntime<TValue>
): NumericalEngineOutcome<TValue> {
  if (!SUPPORTED_NUMERICAL_TOOLS.has(request.tool)) {
    return {
      ok: false,
      issues: [
        {
          code: "numerical.unsupported_tool",
          message: `Unsupported numerical tool '${request.tool}'.`,
          severity: "error",
          field: "tool"
        }
      ]
    };
  }

  const compiled = compileNumericalExpression(request, runtime);
  if (!compiled.ok) {
    return compiled;
  }

  try {
    return request.tool === "differentiate"
      ? differentiate(request, compiled.value, runtime)
      : integrate(request, compiled.value, runtime);
  } catch (error) {
    return {
      ok: false,
      issues: [toNumericalIssue(error)]
    };
  }
}

function compileNumericalExpression<TValue>(
  request: NumericalRequest,
  runtime: NumericRuntime<TValue>
): { ok: true; value: CompiledFunction<TValue> } | { ok: false; issues: ComputationIssue[] } {
  const variables: Record<string, number> = {
    x: request.point ?? request.interval?.[0] ?? 0
  };
  const prepared = prepareExpression(
    {
      expression: request.expression,
      settings: request.settings,
      variables
    },
    runtime
  );

  if (!prepared.evaluate) {
    return {
      ok: false,
      issues: prepared.issues
    };
  }
  const evaluate = prepared.evaluate;

  return {
    ok: true,
    value: {
      canonicalExpression: prepared.canonicalExpression,
      evaluateAt(point) {
        variables.x = point;
        const value = evaluate();
        if (!runtime.isFinite(value)) {
          throw new NumericalComputationError(
            "numerical.non_finite_evaluation",
            `Function evaluation became non-finite near x = ${formatNumber(point)}.`
          );
        }
        return value;
      }
    }
  };
}

function differentiate<TValue>(
  request: NumericalRequest,
  compiled: CompiledFunction<TValue>,
  runtime: NumericRuntime<TValue>
): NumericalEngineOutcome<TValue> {
  const point = requirePoint(request.point);
  const method = request.differentiationMethod ?? "central";
  const tolerance = normalizeTolerance(request.settings.numeric.solverTolerance);
  const maxRefinements = Math.max(2, Math.min(request.settings.numeric.maxIterations, 16));
  let step = initialDerivativeStep(point, tolerance, runtime, method);
  let previousApproximation: number | undefined;
  let best:
    | {
        value: TValue;
        approximateValue: number;
        errorEstimate?: number;
        stepSize: number;
      }
    | undefined;
  let samples = 0;

  for (let refinement = 0; refinement < maxRefinements; refinement += 1) {
    const estimate =
      method === "five-point"
        ? fivePointDerivative(compiled, point, step, runtime)
        : centralDerivative(compiled, point, step, runtime);
    const approximateValue = runtime.toNumber(estimate.value);
    const errorEstimate =
      previousApproximation === undefined
        ? undefined
        : Math.abs(approximateValue - previousApproximation) / (method === "five-point" ? 15 : 3);

    samples += estimate.sampleCount;
    best = {
      value: estimate.value,
      approximateValue,
      stepSize: step
    };
    if (errorEstimate !== undefined) {
      best.errorEstimate = errorEstimate;
    }

    if (errorEstimate !== undefined && errorEstimate <= scaledTolerance(tolerance, approximateValue)) {
      break;
    }

    previousApproximation = approximateValue;
    step /= 2;
  }

  if (!best) {
    throw new NumericalComputationError(
      "numerical.derivative_failed",
      "Derivative estimate could not be computed."
    );
  }

  const issues = buildDerivativeWarnings(compiled, point, best, tolerance, runtime);

  return {
    ok: true,
    value: {
      tool: "differentiate",
      method,
      canonicalExpression: compiled.canonicalExpression,
      value: best.value,
      approximateValue: best.approximateValue,
      sampleCount: samples,
      stepSize: best.stepSize,
      ...(best.errorEstimate !== undefined ? { errorEstimate: best.errorEstimate } : {})
    },
    issues
  };
}

function integrate<TValue>(
  request: NumericalRequest,
  compiled: CompiledFunction<TValue>,
  runtime: NumericRuntime<TValue>
): NumericalEngineOutcome<TValue> {
  const [start, end] = requireInterval(request.interval);
  const method = request.integrationMethod ?? "simpson";
  const tolerance = normalizeTolerance(request.settings.numeric.solverTolerance);

  if (start === end) {
    return {
      ok: true,
      value: {
        tool: "integrate",
        method,
        canonicalExpression: compiled.canonicalExpression,
        value: runtime.zero,
        approximateValue: 0,
        errorEstimate: 0,
        sampleCount: 2,
        stepSize: 0
      },
      issues: []
    };
  }

  const initialPanels = method === "simpson" ? 4 : 2;
  const maxPanels = normalizeMaximumPanels(method, request.settings.numeric.maxIterations);
  let panels = initialPanels;
  let previousApproximation: number | undefined;
  let best:
    | {
        value: TValue;
        approximateValue: number;
        errorEstimate?: number;
        panels: number;
      }
    | undefined;

  while (panels <= maxPanels) {
    const value =
      method === "simpson"
        ? compositeSimpson(compiled, start, end, panels, runtime)
        : compositeTrapezoid(compiled, start, end, panels, runtime);
    const approximateValue = runtime.toNumber(value);
    const errorEstimate =
      previousApproximation === undefined
        ? undefined
        : Math.abs(approximateValue - previousApproximation) / (method === "simpson" ? 15 : 3);

    best = {
      value,
      approximateValue,
      panels
    };
    if (errorEstimate !== undefined) {
      best.errorEstimate = errorEstimate;
    }

    if (errorEstimate !== undefined && errorEstimate <= scaledTolerance(tolerance, approximateValue)) {
      break;
    }

    previousApproximation = approximateValue;
    panels *= 2;
  }

  if (!best) {
    throw new NumericalComputationError(
      "numerical.integration_failed",
      "Integral estimate could not be computed."
    );
  }

  const issues = buildIntegrationWarnings(best, tolerance, maxPanels);

  return {
    ok: true,
    value: {
      tool: "integrate",
      method,
      canonicalExpression: compiled.canonicalExpression,
      value: best.value,
      approximateValue: best.approximateValue,
      sampleCount: best.panels + 1,
      stepSize: Math.abs(end - start) / best.panels,
      ...(best.errorEstimate !== undefined ? { errorEstimate: best.errorEstimate } : {})
    },
    issues
  };
}

function centralDerivative<TValue>(
  compiled: CompiledFunction<TValue>,
  point: number,
  step: number,
  runtime: NumericRuntime<TValue>
): { value: TValue; sampleCount: number } {
  const plus = compiled.evaluateAt(point + step);
  const minus = compiled.evaluateAt(point - step);
  return {
    value: runtime.divide(runtime.subtract(plus, minus), runtime.fromNumber(2 * step)),
    sampleCount: 2
  };
}

function fivePointDerivative<TValue>(
  compiled: CompiledFunction<TValue>,
  point: number,
  step: number,
  runtime: NumericRuntime<TValue>
): { value: TValue; sampleCount: number } {
  const plusTwo = compiled.evaluateAt(point + 2 * step);
  const plusOne = compiled.evaluateAt(point + step);
  const minusOne = compiled.evaluateAt(point - step);
  const minusTwo = compiled.evaluateAt(point - 2 * step);
  const numerator = runtime.add(
    runtime.subtract(runtime.multiply(runtime.fromNumber(8), plusOne), runtime.multiply(runtime.fromNumber(8), minusOne)),
    runtime.subtract(minusTwo, plusTwo)
  );

  return {
    value: runtime.divide(numerator, runtime.fromNumber(12 * step)),
    sampleCount: 4
  };
}

function compositeTrapezoid<TValue>(
  compiled: CompiledFunction<TValue>,
  start: number,
  end: number,
  panels: number,
  runtime: NumericRuntime<TValue>
): TValue {
  const step = (end - start) / panels;
  let total = runtime.add(compiled.evaluateAt(start), compiled.evaluateAt(end));

  for (let index = 1; index < panels; index += 1) {
    total = runtime.add(total, runtime.multiply(runtime.fromNumber(2), compiled.evaluateAt(start + index * step)));
  }

  return runtime.multiply(runtime.divide(runtime.fromNumber(step), runtime.fromNumber(2)), total);
}

function compositeSimpson<TValue>(
  compiled: CompiledFunction<TValue>,
  start: number,
  end: number,
  panels: number,
  runtime: NumericRuntime<TValue>
): TValue {
  const step = (end - start) / panels;
  let total = runtime.add(compiled.evaluateAt(start), compiled.evaluateAt(end));

  for (let index = 1; index < panels; index += 1) {
    const weight = index % 2 === 0 ? 2 : 4;
    total = runtime.add(total, runtime.multiply(runtime.fromNumber(weight), compiled.evaluateAt(start + index * step)));
  }

  return runtime.multiply(runtime.divide(runtime.fromNumber(step), runtime.fromNumber(3)), total);
}

function buildDerivativeWarnings<TValue>(
  compiled: CompiledFunction<TValue>,
  point: number,
  best: {
    approximateValue: number;
    errorEstimate?: number;
    stepSize: number;
  },
  tolerance: number,
  runtime: NumericRuntime<TValue>
): ComputationIssue[] {
  const issues: ComputationIssue[] = [];
  const center = compiled.evaluateAt(point);
  const forward = runtime.toNumber(
    runtime.divide(runtime.subtract(compiled.evaluateAt(point + best.stepSize), center), runtime.fromNumber(best.stepSize))
  );
  const backward = runtime.toNumber(
    runtime.divide(runtime.subtract(center, compiled.evaluateAt(point - best.stepSize)), runtime.fromNumber(best.stepSize))
  );
  const asymmetry = Math.abs(forward - backward);
  const smoothnessThreshold = Math.max(
    10 * (best.errorEstimate ?? 0),
    5 * scaledTolerance(tolerance, best.approximateValue)
  );

  if (asymmetry > smoothnessThreshold) {
    issues.push({
      code: "numerical.point_nonsmooth",
      message: "One-sided derivative estimates disagree strongly near the evaluation point.",
      severity: "warning",
      field: "point"
    });
  }

  if (
    best.errorEstimate === undefined ||
    best.errorEstimate > scaledTolerance(tolerance, best.approximateValue)
  ) {
    issues.push({
      code: "numerical.derivative_unreliable",
      message: "Derivative estimate did not stabilize within the requested tolerance budget.",
      severity: "warning",
      field: "point"
    });
  }

  return issues;
}

function buildIntegrationWarnings(
  best: {
    approximateValue: number;
    errorEstimate?: number;
    panels: number;
  },
  tolerance: number,
  maxPanels: number
): ComputationIssue[] {
  if (
    best.errorEstimate !== undefined &&
    best.errorEstimate <= scaledTolerance(tolerance, best.approximateValue)
  ) {
    return [];
  }

  return [
    {
      code: best.panels >= maxPanels ? "numerical.integration_not_converged" : "numerical.integration_unreliable",
      message:
        best.panels >= maxPanels
          ? "Integral estimate hit the panel budget before meeting the requested tolerance."
          : "Integral estimate remains sensitive to panel refinement.",
      severity: "warning",
      field: "interval"
    }
  ];
}

function requirePoint(point: number | undefined): number {
  if (point === undefined || !Number.isFinite(point)) {
    throw new NumericalComputationError(
      "numerical.point_required",
      "A finite evaluation point is required for differentiation.",
      "point"
    );
  }

  return point;
}

function requireInterval(interval: [number, number] | undefined): [number, number] {
  if (!interval || interval.length !== 2 || !interval.every((value) => Number.isFinite(value))) {
    throw new NumericalComputationError(
      "numerical.interval_required",
      "A finite interval is required for integration.",
      "interval"
    );
  }

  return interval;
}

function initialDerivativeStep<TValue>(
  point: number,
  tolerance: number,
  runtime: NumericRuntime<TValue>,
  method: DifferentiationMethod
): number {
  const scale = Math.max(1, Math.abs(point));
  const orderExponent = method === "five-point" ? 1 / 5 : 1 / 3;
  const toleranceStep = Math.pow(tolerance, orderExponent) * scale;
  const precisionDigits = runtime.backend === "decimal" ? Math.min(runtime.internalPrecision, 48) : 15;
  const precisionFloor = Math.pow(10, -Math.max(3, Math.floor(precisionDigits / 2))) * scale;

  return Math.max(toleranceStep, precisionFloor, 1e-6 * scale);
}

function normalizeMaximumPanels(method: IntegrationMethod, maxIterations: number): number {
  const minimumPanels = method === "simpson" ? 4 : 2;
  const capped = Math.max(minimumPanels, Math.min(Math.trunc(maxIterations), 4096));
  let panels = minimumPanels;

  while (panels * 2 <= capped) {
    panels *= 2;
  }

  return panels;
}

function normalizeTolerance(tolerance: number): number {
  return Number.isFinite(tolerance) && tolerance > 0 ? tolerance : 1e-10;
}

function scaledTolerance(tolerance: number, magnitude: number): number {
  return tolerance * Math.max(1, Math.abs(magnitude));
}

function toNumericalIssue(error: unknown): ComputationIssue {
  if (error instanceof NumericalComputationError) {
    return {
      code: error.code,
      message: error.message,
      severity: "error",
      field: error.field
    };
  }

  return toComputationIssue(error);
}

function formatNumber(value: number): string {
  return Number.isFinite(value) ? Number.parseFloat(value.toPrecision(10)).toString() : String(value);
}

import type {
  CalculationService,
  ExpressionRequest,
  ExpressionResult,
  ResultEnvelope
} from "@core/contracts";
import { prepareExpression } from "@core/expression";
import {
  createDecimalRuntime,
  createFloat64Runtime,
  normalizeNumericSettings,
  type NumericRuntime
} from "@core/precision";
import { toComputationIssue } from "@core/expression/compiler";

export function createCalculationService(): CalculationService {
  return {
    calculate(request) {
      const startedAt = now();
      const normalizedRequest = {
        ...request,
        settings: {
          ...request.settings,
          numeric: normalizeNumericSettings(request.settings.numeric)
        }
      };

      if (normalizedRequest.settings.numeric.backend === "decimal") {
        return executeWithRuntime(normalizedRequest, createDecimalRuntime(normalizedRequest.settings.numeric), startedAt);
      }

      return executeWithRuntime(normalizedRequest, createFloat64Runtime(normalizedRequest.settings.numeric), startedAt);
    }
  };
}

function executeWithRuntime<TValue>(
  request: ExpressionRequest,
  runtime: NumericRuntime<TValue>,
  startedAt: number
): ResultEnvelope<ExpressionResult> {
  const prepared = prepareExpression(request, runtime);

  if (!prepared.evaluate) {
    return {
      ok: false,
      issues: prepared.issues,
      metadata: {
        backend: runtime.backend,
        elapsedMs: now() - startedAt
      }
    };
  }

  try {
    const value = prepared.evaluate();

    if (!runtime.isFinite(value)) {
      return {
        ok: false,
        issues: [
          {
            code: "math.non_finite",
            message: "The expression evaluated to a non-finite number.",
            severity: "error",
            field: "expression"
          }
        ],
        metadata: {
          backend: runtime.backend,
          elapsedMs: now() - startedAt
        }
      };
    }

    return {
      ok: true,
      value: {
        canonicalExpression: prepared.canonicalExpression,
        formattedValue: runtime.toDisplayString(
          value,
          request.settings.numeric.displayMode,
          request.settings.numeric.displayPrecision
        ),
        approximateValue: runtime.toNumber(value)
      },
      issues: [],
      metadata: {
        backend: runtime.backend,
        elapsedMs: now() - startedAt
      }
    };
  } catch (error) {
    return {
      ok: false,
      issues: [toComputationIssue(error)],
      metadata: {
        backend: runtime.backend,
        elapsedMs: now() - startedAt
      }
    };
  }
}

function now(): number {
  return globalThis.performance?.now() ?? Date.now();
}

import type {
  SolverIteration,
  SolverMethod,
  SolverTerminationReason
} from "@core/contracts";
import type { NumericRuntime } from "@core/precision";

const DEFAULT_TOLERANCE = 1e-10;
const MIN_DERIVATIVE = 1e-14;

export class SolverComputationError extends Error {
  constructor(
    readonly code: string,
    message: string,
    readonly field?: string
  ) {
    super(message);
  }
}

export interface SolverEngineRequest<TValue> {
  method: SolverMethod;
  runtime: NumericRuntime<TValue>;
  evaluate(value: TValue): TValue;
  tolerance: number;
  maxIterations: number;
  initialGuess?: number;
  bracket?: [number, number];
}

export interface RootSolveResult<TValue> {
  root: TValue;
  residual: TValue;
  iterations: number;
  converged: boolean;
  tolerance: number;
  maxIterations: number;
  terminationReason: SolverTerminationReason;
  history: SolverIteration[];
}

export function solveRoot<TValue>(request: SolverEngineRequest<TValue>): RootSolveResult<TValue> {
  const normalized = {
    ...request,
    tolerance: normalizeTolerance(request.tolerance),
    maxIterations: normalizeMaxIterations(request.maxIterations)
  };

  switch (normalized.method) {
    case "newton":
      return solveWithNewton(normalized);
    case "bisection":
      return solveWithBisection(normalized);
  }
}

function solveWithNewton<TValue>(request: SolverEngineRequest<TValue>): RootSolveResult<TValue> {
  const { runtime } = request;
  const history: SolverIteration[] = [];
  const initialGuess = request.initialGuess;

  if (typeof initialGuess !== "number" || !Number.isFinite(initialGuess)) {
    throw new SolverComputationError(
      "solver_initial_guess_required",
      "Newton-Raphson requires a finite initial guess.",
      "initialGuess"
    );
  }

  let current = runtime.fromNumber(initialGuess);

  for (let iteration = 0; iteration < request.maxIterations; iteration += 1) {
    const value = evaluateFinite(request, current);
    const residual = runtime.abs(value);
    const residualNumber = toMagnitude(runtime, residual);

    if (residualNumber <= request.tolerance) {
      history.push({
        iteration,
        estimate: runtime.toNumber(current),
        residual: residualNumber,
        step: 0
      });

      return {
        root: current,
        residual,
        iterations: iteration,
        converged: true,
        tolerance: request.tolerance,
        maxIterations: request.maxIterations,
        terminationReason: "residual_tolerance",
        history
      };
    }

    const stepSize = estimateDerivativeStep(runtime.toNumber(current), request.tolerance);
    const step = runtime.fromNumber(stepSize);
    const forward = evaluateFinite(request, runtime.add(current, step));
    const backward = evaluateFinite(request, runtime.subtract(current, step));
    const derivative = runtime.divide(
      runtime.subtract(forward, backward),
      runtime.multiply(runtime.fromNumber(2), step)
    );
    const derivativeNumber = runtime.toNumber(derivative);

    history.push({
      iteration,
      estimate: runtime.toNumber(current),
      residual: residualNumber,
      derivative: derivativeNumber
    });

    if (!Number.isFinite(derivativeNumber) || Math.abs(derivativeNumber) <= Math.max(request.tolerance, MIN_DERIVATIVE)) {
      return {
        root: current,
        residual,
        iterations: iteration,
        converged: false,
        tolerance: request.tolerance,
        maxIterations: request.maxIterations,
        terminationReason: "zero_derivative",
        history
      };
    }

    const next = runtime.subtract(current, runtime.divide(value, derivative));
    if (!runtime.isFinite(next)) {
      throw new SolverComputationError(
        "solver_non_finite",
        "The solver produced a non-finite estimate.",
        "expression"
      );
    }

    const stepMagnitude = toMagnitude(runtime, runtime.subtract(next, current));
    history[history.length - 1]!.step = stepMagnitude;
    current = next;
  }

  const residual = runtime.abs(evaluateFinite(request, current));
  history.push({
    iteration: request.maxIterations,
    estimate: runtime.toNumber(current),
    residual: toMagnitude(runtime, residual),
    step: 0
  });

  return {
    root: current,
    residual,
    iterations: request.maxIterations,
    converged: false,
    tolerance: request.tolerance,
    maxIterations: request.maxIterations,
    terminationReason: "max_iterations",
    history
  };
}

function solveWithBisection<TValue>(request: SolverEngineRequest<TValue>): RootSolveResult<TValue> {
  const { runtime } = request;
  const history: SolverIteration[] = [];
  const bracket = request.bracket;

  if (!bracket) {
    throw new SolverComputationError(
      "solver_bracket_required",
      "Bisection requires lower and upper interval bounds.",
      "bracket"
    );
  }

  let [lowerNumber, upperNumber] = bracket;
  if (!Number.isFinite(lowerNumber) || !Number.isFinite(upperNumber)) {
    throw new SolverComputationError(
      "solver_invalid_bracket",
      "Bisection interval bounds must be finite numbers.",
      "bracket"
    );
  }

  if (lowerNumber >= upperNumber) {
    throw new SolverComputationError(
      "solver_invalid_bracket",
      "Bisection requires the lower bound to stay below the upper bound.",
      "bracket"
    );
  }

  let lower = runtime.fromNumber(lowerNumber);
  let upper = runtime.fromNumber(upperNumber);
  let lowerValue = evaluateFinite(request, lower);
  let upperValue = evaluateFinite(request, upper);
  const lowerResidual = toMagnitude(runtime, runtime.abs(lowerValue));
  const upperResidual = toMagnitude(runtime, runtime.abs(upperValue));

  if (lowerResidual <= request.tolerance) {
    return {
      root: lower,
      residual: runtime.abs(lowerValue),
      iterations: 0,
      converged: true,
      tolerance: request.tolerance,
      maxIterations: request.maxIterations,
      terminationReason: "exact_endpoint",
      history: [
        {
          iteration: 0,
          estimate: lowerNumber,
          residual: lowerResidual,
          lowerBound: lowerNumber,
          upperBound: upperNumber
        }
      ]
    };
  }

  if (upperResidual <= request.tolerance) {
    return {
      root: upper,
      residual: runtime.abs(upperValue),
      iterations: 0,
      converged: true,
      tolerance: request.tolerance,
      maxIterations: request.maxIterations,
      terminationReason: "exact_endpoint",
      history: [
        {
          iteration: 0,
          estimate: upperNumber,
          residual: upperResidual,
          lowerBound: lowerNumber,
          upperBound: upperNumber
        }
      ]
    };
  }

  if (sameSign(runtime.toNumber(lowerValue), runtime.toNumber(upperValue))) {
    throw new SolverComputationError(
      "solver_invalid_bracket",
      "Bisection requires the interval bounds to bracket a sign change.",
      "bracket"
    );
  }

  let midpoint = lower;
  let midpointValue = lowerValue;

  for (let iteration = 1; iteration <= request.maxIterations; iteration += 1) {
    midpoint = runtime.divide(runtime.add(lower, upper), runtime.fromNumber(2));
    midpointValue = evaluateFinite(request, midpoint);

    const midpointNumber = runtime.toNumber(midpoint);
    const residualNumber = toMagnitude(runtime, runtime.abs(midpointValue));
    lowerNumber = runtime.toNumber(lower);
    upperNumber = runtime.toNumber(upper);

    history.push({
      iteration,
      estimate: midpointNumber,
      residual: residualNumber,
      lowerBound: lowerNumber,
      upperBound: upperNumber,
      step: Math.abs(upperNumber - lowerNumber) / 2
    });

    if (residualNumber <= request.tolerance) {
      return {
        root: midpoint,
        residual: runtime.abs(midpointValue),
        iterations: iteration,
        converged: true,
        tolerance: request.tolerance,
        maxIterations: request.maxIterations,
        terminationReason: "residual_tolerance",
        history
      };
    }

    if (Math.abs(upperNumber - lowerNumber) / 2 <= request.tolerance) {
      return {
        root: midpoint,
        residual: runtime.abs(midpointValue),
        iterations: iteration,
        converged: true,
        tolerance: request.tolerance,
        maxIterations: request.maxIterations,
        terminationReason: "interval_tolerance",
        history
      };
    }

    if (sameSign(runtime.toNumber(lowerValue), runtime.toNumber(midpointValue))) {
      lower = midpoint;
      lowerValue = midpointValue;
    } else {
      upper = midpoint;
      upperValue = midpointValue;
    }
  }

  return {
    root: midpoint,
    residual: runtime.abs(midpointValue),
    iterations: request.maxIterations,
    converged: false,
    tolerance: request.tolerance,
    maxIterations: request.maxIterations,
    terminationReason: "max_iterations",
    history
  };
}

function normalizeTolerance(value: number): number {
  return Number.isFinite(value) && value > 0 ? value : DEFAULT_TOLERANCE;
}

function normalizeMaxIterations(value: number): number {
  if (!Number.isFinite(value) || value < 1) {
    return 100;
  }

  return Math.max(1, Math.trunc(value));
}

function estimateDerivativeStep(estimate: number, tolerance: number): number {
  return Math.max(Math.sqrt(tolerance), 1e-7) * Math.max(1, Math.abs(estimate));
}

